const body = $json.body ?? {};
const now = new Date().toISOString();
const idPart = Math.random().toString(16).slice(2, 10);
const jobId = `job_${Date.now()}_${idPart}`;
const mode = body.mode === 'standard' ? 'standard' : 'default';

const topic = typeof body.topic === 'string' && body.topic.trim()
  ? body.topic.trim()
  : (typeof body.prompt === 'string' ? body.prompt.trim() : '');

const requirements = Array.isArray(body.requirements)
  ? body.requirements.filter((v) => typeof v === 'string' && v.trim()).map((v) => v.trim())
  : [];

const payload = {
  topic,
  requirements,
  page_size: Number(body.page_size ?? 15),
  sort: typeof body.sort === 'string' && body.sort ? body.sort : 'general'
};

const store = getWorkflowStaticData('global');
store[jobId] = {
  jobId,
  status: 'running',
  progress: 10,
  message: '任务已创建，等待执行',
  mode,
  createdAt: now,
  updatedAt: now,
  input: body
};

return [{
  json: {
    jobId,
    mode,
    payload,
    autoImage: !!body.autoImage,
    prompt: body.prompt ?? ''
  }
}];

const { jobId, payload } = $json;
const store = getWorkflowStaticData('global');

if (!jobId) {
  return [{ json: { ok: false, error: 'missing jobId' } }];
}

store[jobId] = {
  ...(store[jobId] ?? {}),
  status: 'running',
  progress: 30,
  message: '正在请求 Python 服务',
  updatedAt: new Date().toISOString()
};

try {
  const res = await fetch('http://127.0.0.1:8001/search/poll', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  });

  const raw = await res.text();
  let data;
  try {
    data = JSON.parse(raw);
  } catch {
    data = { raw };
  }

  if (!res.ok) {
    store[jobId] = {
      ...(store[jobId] ?? {}),
      status: 'failed',
      progress: 100,
      error: `Python 服务失败(${res.status})`,
      message: '下游服务返回错误',
      result: data,
      updatedAt: new Date().toISOString()
    };
    return [{ json: { ok: false, jobId, result: data } }];
  }

  store[jobId] = {
    ...(store[jobId] ?? {}),
    status: 'done',
    progress: 100,
    message: '任务完成',
    result: data,
    updatedAt: new Date().toISOString()
  };

  return [{ json: { ok: true, jobId, result: data } }];
} catch (error) {
  const message = error instanceof Error ? error.message : 'unknown error';
  store[jobId] = {
    ...(store[jobId] ?? {}),
    status: 'failed',
    progress: 100,
    error: message,
    message: '执行失败',
    updatedAt: new Date().toISOString()
  };
  return [{ json: { ok: false, jobId, error: message } }];
}

const query = $json.query ?? {};
const jobId = String(query.jobId ?? '').trim();
const store = getWorkflowStaticData('global');

if (!jobId) {
  return [{
    json: {
      jobId: '',
      status: 'failed',
      error: '缺少 jobId'
    }
  }];
}

const hit = store[jobId];
if (!hit) {
  return [{
    json: {
      jobId,
      status: 'pending',
      progress: 0,
      message: '任务不存在或尚未初始化'
    }
  }];
}

return [{
  json: {
    jobId,
    status: hit.status ?? 'pending',
    progress: hit.progress ?? 0,
    message: hit.message ?? '',
    result: hit.result,
    error: hit.error
  }
}];
